//! Integration tests for layout caching functionality

use std::fs;
use std::time::Instant;
use tempfile::TempDir;
use templateflow::{ls, templates};

#[test]
#[ignore] // Requires network access
fn test_layout_cache_performance() {
    // Create a temporary home directory
    let temp_dir = TempDir::new().unwrap();
    std::env::set_var("TEMPLATEFLOW_HOME", temp_dir.path());

    // First run - should be slower (parsing skeleton)
    let start = Instant::now();
    let templates1 = templates(None).unwrap();
    let first_duration = start.elapsed();

    // Verify we got templates
    assert!(!templates1.is_empty());

    // Second run - should be faster (loading from cache)
    // Note: We need to clear the in-memory cache to test file cache
    // In a real scenario, this would happen between program runs

    // Check that cache files were created
    let cache_dir = temp_dir.path().join(".cache");
    assert!(cache_dir.exists());

    let cache_file = cache_dir.join("layout.bincode");
    let metadata_file = cache_dir.join("layout_metadata.json");
    assert!(cache_file.exists(), "Cache file should exist");
    assert!(metadata_file.exists(), "Metadata file should exist");

    println!("First run took: {:?}", first_duration);
    println!("Cache file size: {} bytes", fs::metadata(&cache_file).unwrap().len());
}

#[test]
#[ignore] // Requires network access
fn test_cache_invalidation_on_skeleton_update() {
    let temp_dir = TempDir::new().unwrap();
    std::env::set_var("TEMPLATEFLOW_HOME", temp_dir.path());

    // Initial load
    let templates1 = templates(None).unwrap();
    assert!(!templates1.is_empty());

    // Verify cache was created
    let cache_file = temp_dir.path().join(".cache/layout.bincode");
    assert!(cache_file.exists());

    // Get initial cache modification time
    let initial_mtime = fs::metadata(&cache_file).unwrap().modified().unwrap();

    // Modify the skeleton file to trigger cache invalidation
    let skeleton_path = temp_dir.path().join("templateflow-skel.zip");
    assert!(skeleton_path.exists());

    // Sleep briefly to ensure different timestamp
    std::thread::sleep(std::time::Duration::from_millis(100));

    // Touch the skeleton file to change its modification time
    let skeleton_content = fs::read(&skeleton_path).unwrap();
    fs::write(&skeleton_path, &skeleton_content).unwrap();

    // Clear in-memory cache and reload
    drop(templates1);
    let _ = ls("MNI152Lin", None).unwrap();

    // Cache should have been recreated
    let new_mtime = fs::metadata(&cache_file).unwrap().modified().unwrap();
    assert!(new_mtime > initial_mtime, "Cache should have been recreated");
}

#[test]
fn test_cache_with_invalid_data() {
    let temp_dir = TempDir::new().unwrap();
    std::env::set_var("TEMPLATEFLOW_HOME", temp_dir.path());

    // Create cache directory
    let cache_dir = temp_dir.path().join(".cache");
    fs::create_dir_all(&cache_dir).unwrap();

    // Write invalid cache data
    let cache_file = cache_dir.join("layout.bincode");
    fs::write(&cache_file, b"invalid binary data").unwrap();

    let metadata_file = cache_dir.join("layout_metadata.json");
    fs::write(&metadata_file, r#"{"invalid": "json"}"#).unwrap();

    // Should handle invalid cache gracefully and fall back to loading from skeleton
    // This will fail because skeleton doesn't exist, but it proves cache was skipped
    let result = templates(None);
    assert!(result.is_err());
}

