//! Layout caching for improved performance
//!
//! This module provides caching functionality for the TemplateLayout to avoid
//! repeatedly parsing the skeleton zip file on every API call.

use crate::bids::TemplateLayout;
use crate::config::CONFIG;
use crate::error::{Result, TemplateFlowError};
use serde::{Deserialize, Serialize};
use std::fs;
use std::path::{Path, PathBuf};
use std::time::SystemTime;

/// Layout cache metadata
#[derive(Debug, Serialize, Deserialize)]
struct CacheMetadata {
    /// Version of the cache format
    version: u32,
    /// Timestamp when the cache was created
    created_at: SystemTime,
    /// MD5 hash of the skeleton file
    skeleton_hash: String,
    /// Size of the skeleton file
    skeleton_size: u64,
}

impl CacheMetadata {
    const CURRENT_VERSION: u32 = 1;

    /// Create new cache metadata for the current skeleton
    fn from_skeleton(skeleton_path: &Path) -> Result<Self> {
        let metadata = fs::metadata(skeleton_path)?;
        let skeleton_size = metadata.len();

        // Calculate MD5 hash of the skeleton file
        let skeleton_hash = calculate_file_hash(skeleton_path)?;

        Ok(Self {
            version: Self::CURRENT_VERSION,
            created_at: SystemTime::now(),
            skeleton_hash,
            skeleton_size,
        })
    }

    /// Check if this cache is valid for the current skeleton
    fn is_valid_for(&self, skeleton_path: &Path) -> Result<bool> {
        // Check version
        if self.version != Self::CURRENT_VERSION {
            return Ok(false);
        }

        // Check file size first (fast check)
        let metadata = fs::metadata(skeleton_path)?;
        if metadata.len() != self.skeleton_size {
            return Ok(false);
        }

        // Check hash (slower but definitive)
        let current_hash = calculate_file_hash(skeleton_path)?;
        Ok(current_hash == self.skeleton_hash)
    }
}

/// Layout cache manager
pub struct LayoutCache {
    /// Path to the cache file
    cache_path: PathBuf,
    /// Path to the metadata file
    metadata_path: PathBuf,
}

impl LayoutCache {
    /// Create a new layout cache instance
    pub fn new() -> Self {
        let cache_dir = CONFIG.home.join(".cache");
        fs::create_dir_all(&cache_dir).ok();

        Self {
            cache_path: cache_dir.join("layout.bincode"),
            metadata_path: cache_dir.join("layout_metadata.json"),
        }
    }

    /// Load layout from cache if valid
    pub fn load(&self) -> Result<Option<TemplateLayout>> {
        // Check if cache files exist
        if !self.cache_path.exists() || !self.metadata_path.exists() {
            return Ok(None);
        }

        // Load and validate metadata
        let metadata_str = fs::read_to_string(&self.metadata_path)?;
        let metadata: CacheMetadata = serde_json::from_str(&metadata_str)
            .map_err(|e| TemplateFlowError::CacheError(format!("Invalid cache metadata: {}", e)))?;

        // Check if cache is valid for current skeleton
        let skeleton_path = CONFIG.skeleton_path();
        if !metadata.is_valid_for(&skeleton_path)? {
            // Cache is outdated
            return Ok(None);
        }

        // Load the cached layout
        let cache_data = fs::read(&self.cache_path)?;
        let layout: TemplateLayout = bincode::deserialize(&cache_data)
            .map_err(|e| TemplateFlowError::CacheError(format!("Failed to deserialize cache: {}", e)))?;

        Ok(Some(layout))
    }

    /// Save layout to cache
    pub fn save(&self, layout: &TemplateLayout) -> Result<()> {
        let skeleton_path = CONFIG.skeleton_path();

        // Create cache metadata
        let metadata = CacheMetadata::from_skeleton(&skeleton_path)?;

        // Serialize and save metadata
        let metadata_json = serde_json::to_string_pretty(&metadata)
            .map_err(|e| TemplateFlowError::CacheError(format!("Failed to serialize metadata: {}", e)))?;
        fs::write(&self.metadata_path, metadata_json)?;

        // Serialize and save layout
        let layout_data = bincode::serialize(layout)
            .map_err(|e| TemplateFlowError::CacheError(format!("Failed to serialize layout: {}", e)))?;
        fs::write(&self.cache_path, layout_data)?;

        Ok(())
    }

    /// Clear the cache
    pub fn clear(&self) -> Result<()> {
        if self.cache_path.exists() {
            fs::remove_file(&self.cache_path)?;
        }
        if self.metadata_path.exists() {
            fs::remove_file(&self.metadata_path)?;
        }
        Ok(())
    }
}

/// Calculate MD5 hash of a file
fn calculate_file_hash(path: &Path) -> Result<String> {
    use std::io::Read;

    let mut file = fs::File::open(path)?;
    let mut hasher = md5::Context::new();
    let mut buffer = [0; 8192];

    loop {
        let bytes_read = file.read(&mut buffer)?;
        if bytes_read == 0 {
            break;
        }
        hasher.consume(&buffer[..bytes_read]);
    }

    Ok(format!("{:x}", hasher.compute()))
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::bids::{TemplateFile, TemplateMetadata};
    use tempfile::TempDir;

    #[test]
    fn test_cache_save_and_load() {
        let temp_dir = TempDir::new().unwrap();
        std::env::set_var("TEMPLATEFLOW_HOME", temp_dir.path());

        // Create a dummy skeleton file
        let skeleton_path = temp_dir.path().join("templateflow-skel.zip");
        fs::write(&skeleton_path, b"dummy content").unwrap();

        // Create a test layout
        let mut layout = TemplateLayout::new();
        let file = TemplateFile {
            path: PathBuf::from("tpl-test/tpl-test_T1w.nii.gz"),
            template: "test".to_string(),
            entities: [("tpl".to_string(), "test".to_string())].into_iter().collect(),
            suffix: Some("T1w".to_string()),
            extension: Some("nii.gz".to_string()),
        };
        layout.add_file(file);

        // Test cache operations
        let cache = LayoutCache::new();

        // Initially, cache should be empty
        assert!(cache.load().unwrap().is_none());

        // Save to cache
        cache.save(&layout).unwrap();

        // Load from cache
        let loaded = cache.load().unwrap().expect("Cache should exist");
        assert_eq!(loaded.templates.len(), 1);
        let templates: Vec<&str> = loaded.get_templates();
        assert_eq!(templates, vec!["test"]);

        // Clear cache
        cache.clear().unwrap();
        assert!(cache.load().unwrap().is_none());
    }

    #[test]
    fn test_cache_invalidation() {
        let temp_dir = TempDir::new().unwrap();
        std::env::set_var("TEMPLATEFLOW_HOME", temp_dir.path());

        // Create a dummy skeleton file
        let skeleton_path = temp_dir.path().join("templateflow-skel.zip");
        fs::write(&skeleton_path, b"original content").unwrap();

        // Create and save a layout
        let layout = TemplateLayout::new();
        let cache = LayoutCache::new();
        cache.save(&layout).unwrap();

        // Verify cache is valid
        assert!(cache.load().unwrap().is_some());

        // Modify skeleton file
        fs::write(&skeleton_path, b"modified content").unwrap();

        // Cache should now be invalid
        assert!(cache.load().unwrap().is_none());
    }
}

